/**
 * 3D SPATIAL GEOMETRY ENGINE
 * Provides a high-density, interactive background with neural connectivity and fractal depths.
 */
function TeamFractalBackground() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [mouse, setMouse] = useState({ x: 0, y: 0, targetX: 0, targetY: 0 });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let particles: Particle[] = [];
    let animationFrameId: number;

    class Particle {
      x: number; y: number; z: number;
      vx: number; vy: number; vz: number;
      baseX: number; baseY: number;

      constructor() {
        this.x = Math.random() * canvas!.width;
        this.y = Math.random() * canvas!.height;
        this.z = Math.random() * 1000;
        this.vx = (Math.random() - 0.5) * 0.5;
        this.vy = (Math.random() - 0.5) * 0.5;
        this.vz = (Math.random() - 0.5) * 0.5;
        this.baseX = this.x;
        this.baseY = this.y;
      }

      update(mX: number, mY: number) {
        this.x += this.vx + (mX * 0.02);
        this.y += this.vy + (mY * 0.02);
        this.z += this.vz;

        if (this.x < 0 || this.x > canvas!.width) this.vx *= -1;
        if (this.y < 0 || this.y > canvas!.height) this.vy *= -1;
        if (this.z < 0 || this.z > 1000) this.vz *= -1;
      }

      draw() {
        const scale = 1000 / (1000 + this.z);
        const r = 1.5 * scale;
        ctx!.beginPath();
        ctx!.arc(this.x, this.y, r, 0, Math.PI * 2);
        ctx!.fillStyle = `rgba(59, 130, 246, ${0.2 * scale})`;
        ctx!.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      particles = Array.from({ length: 150 }, () => new Particle());
    };

    const drawLines = () => {
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < 150) {
            const opacity = (1 - dist / 150) * 0.15;
            ctx!.beginPath();
            ctx!.strokeStyle = `rgba(59, 130, 246, ${opacity})`;
            ctx!.lineWidth = 0.5;
            ctx!.moveTo(particles[i].x, particles[i].y);
            ctx!.lineTo(particles[j].x, particles[j].y);
            ctx!.stroke();
          }
        }
      }
    };

    const animate = () => {
      ctx!.clearRect(0, 0, canvas.width, canvas.height);
      setMouse(prev => ({
        ...prev,
        x: prev.x + (prev.targetX - prev.x) * 0.05,
        y: prev.y + (prev.targetY - prev.y) * 0.05
      }));
      
      particles.forEach(p => {
        p.update(mouse.x, mouse.y);
        p.draw();
      });
      drawLines();
      animationFrameId = requestAnimationFrame(animate);
    };

    const handleResize = () => init();
    const handleMove = (e: MouseEvent) => {
      setMouse(prev => ({ ...prev, targetX: e.clientX - window.innerWidth / 2, targetY: e.clientY - window.innerHeight / 2 }));
    };

    window.addEventListener("resize", handleResize);
    window.addEventListener("mousemove", handleMove);
    init();
    animate();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("mousemove", handleMove);
    };
  }, [mouse.x, mouse.y]);

  return (
    <div className="absolute inset-0 z-0 bg-[#030712] overflow-hidden">
      <canvas ref={canvasRef} className="absolute inset-0 opacity-40" />
      
      {/* Layered Floating Geometry */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none">
        <defs>
          <filter id="glassBlur">
            <feGaussianBlur stdDeviation="15" />
          </filter>
          <linearGradient id="crystalGrad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#1e40af" stopOpacity="0.1" />
            <stop offset="100%" stopColor="#3b82f6" stopOpacity="0.05" />
          </linearGradient>
        </defs>

        {/* Moving Background Shards */}
        <g style={{ transform: `translate(${mouse.x * -0.05}px, ${mouse.y * -0.05}px)` }} className="transition-transform duration-1000">
          <path d="M-100,200 L300,50 L500,400 Z" fill="url(#crystalGrad)" stroke="rgba(255,255,255,0.05)" />
          <path d="M1200,600 L1500,300 L1700,800 Z" fill="url(#crystalGrad)" stroke="rgba(255,255,255,0.05)" />
          <circle cx="20%" cy="40%" r="200" fill="rgba(30,64,175,0.05)" filter="url(#glassBlur)" />
          <circle cx="80%" cy="60%" r="250" fill="rgba(59,130,246,0.03)" filter="url(#glassBlur)" />
        </g>
      </svg>

      {/* Surface Depth Mask */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#030712_85%)]" />
    </div>
  );
}

